const apiKey = 'c1a97f1ab80dc87908bd6f479d0d4ff97233c6dfd04b0e1e61db56f612e818b3';
const baseUrl = 'https://api.wavespeed.ai/api/v3';

const body = $input.first().json.body || $input.first().json;
const sessionId = body.session_id || '';
const descriptions = body.descriptions || [];

if (!descriptions.length) throw new Error('descriptions must be a non-empty array');

const results = [];

for (const description of descriptions) {
  let taskId;
  try {
    const submitRes = await fetch(`${baseUrl}/wavespeed-ai/flux-dev/text-to-image`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ inputs: { prompt: description, size: '1024*1024', num_images: 1 }, enable_safety_checker: true })
    });
    const submitData = await submitRes.json();
    if (!submitData.data?.id) throw new Error('No task ID: ' + JSON.stringify(submitData));
    taskId = submitData.data.id;
  } catch (err) {
    results.push({ id: null, description, url: null, status: 'submit_error', error: err.message });
    continue;
  }

  let result = { status: 'timeout', url: null };
  for (let i = 0; i < 40; i++) {
    await new Promise(r => setTimeout(r, 5000));
    const pollRes = await fetch(`${baseUrl}/predictions/${taskId}`, {
      headers: { 'Authorization': `Bearer ${apiKey}` }
    });
    const pollData = await pollRes.json();
    const status = pollData.data?.status;
    if (status === 'succeeded') { result = { status, url: pollData.data.outputs?.[0] || null }; break; }
    if (status === 'failed') { result = { status, url: null }; break; }
  }
  results.push({ id: taskId, description, url: result.url, status: result.status });
}

return [{ json: { session_id: sessionId, images: results } }];
